-- ClickHouse Decimal512 比较运算测试 - 区块链场景
-- 测试内容：比较操作、排序、索引、不同类型之间的运算

SELECT '=== Decimal512 比较运算测试 - 区块链场景 ===' as test_section;

-- ==============================================
-- 1. 基本比较操作测试
-- ==============================================

SELECT '=== 基本比较操作测试 ===' as test_section;

-- 1.1 相等比较 (=)
SELECT
    toDecimal512('123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789', 0) =
    toDecimal512('123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789', 0) as equality_test,

    toDecimal512('1000000.000000000000000000', 18) =
    toDecimal512('1000000.000000000000000000', 18) as token_balance_equality,

    toDecimal512('21000.000000000000', 12) =
    toDecimal512('21000.000000000000', 12) as gas_fee_equality;

-- 1.2 不等比较 (!= 或 <>)
SELECT
    toDecimal512('123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789', 0) !=
    toDecimal512('987654321098765432109876543210987654321098765432109876543210987654321098765432109876543210987654321098765432109876543210987654321', 0) as inequality_test,

    toDecimal512('1000000.000000000000000000', 18) <>
    toDecimal512('500000.000000000000000000', 18) as token_balance_inequality;

-- 1.3 大于比较 (>)
SELECT
    toDecimal512('123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789', 0) >
    toDecimal512('987654321098765432109876543210987654321098765432109876543210987654321098765432109876543210987654321098765432109876543210987654321', 0) as greater_than_test,

    toDecimal512('1000000.000000000000000000', 18) >
    toDecimal512('500000.000000000000000000', 18) as token_balance_greater_than;

-- 1.4 小于比较 (<)
SELECT
    toDecimal512('987654321098765432109876543210987654321098765432109876543210987654321098765432109876543210987654321098765432109876543210987654321', 0) <
    toDecimal512('123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789', 0) as less_than_test,

    toDecimal512('500000.000000000000000000', 18) <
    toDecimal512('1000000.000000000000000000', 18) as token_balance_less_than;

-- 1.5 大于等于比较 (>=)
SELECT
    toDecimal512('123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789', 0) >=
    toDecimal512('123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789', 0) as greater_equal_test,

    toDecimal512('1000000.000000000000000000', 18) >=
    toDecimal512('500000.000000000000000000', 18) as token_balance_greater_equal;

-- 1.6 小于等于比较 (<=)
SELECT
    toDecimal512('123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789', 0) <=
    toDecimal512('123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789', 0) as less_equal_test,

    toDecimal512('500000.000000000000000000', 18) <=
    toDecimal512('1000000.000000000000000000', 18) as token_balance_less_equal;

-- ==============================================
-- 2. 排序测试
-- ==============================================

SELECT '=== 排序测试 ===' as test_section;

-- 2.1 升序排序测试
SELECT
    arraySort([toDecimal512('1000000.000000000000000000', 18),
               toDecimal512('500000.000000000000000000', 18),
               toDecimal512('2000000.000000000000000000', 18),
               toDecimal512('750000.000000000000000000', 18)]) as ascending_sort;

-- 2.2 降序排序测试
SELECT
    arrayReverseSort([toDecimal512('1000000.000000000000000000', 18),
                      toDecimal512('500000.000000000000000000', 18),
                      toDecimal512('2000000.000000000000000000', 18),
                      toDecimal512('750000.000000000000000000', 18)]) as descending_sort;

-- 2.3 大数值排序测试
SELECT
    arraySort([toDecimal512('999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999', 0),
               toDecimal512('123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789', 0),
               toDecimal512('987654321098765432109876543210987654321098765432109876543210987654321098765432109876543210987654321098765432109876543210987654321', 0)]) as large_number_sort;

-- ==============================================
-- 3. 最小值/最大值聚合测试
-- ==============================================

SELECT '=== 最小值/最大值聚合测试 ===' as test_section;

-- 3.1 最小值聚合
SELECT
    arrayMin([toDecimal512('1000000.000000000000000000', 18),
              toDecimal512('500000.000000000000000000', 18),
              toDecimal512('2000000.000000000000000000', 18),
              toDecimal512('750000.000000000000000000', 18)]) as min_aggregation;

-- 3.2 最大值聚合
SELECT
    arrayMax([toDecimal512('1000000.000000000000000000', 18),
              toDecimal512('500000.000000000000000000', 18),
              toDecimal512('2000000.000000000000000000', 18),
              toDecimal512('750000.000000000000000000', 18)]) as max_aggregation;

-- 3.3 大数值最小值/最大值聚合
SELECT
    arrayMin([toDecimal512('999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999', 0),
              toDecimal512('123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789', 0),
              toDecimal512('987654321098765432109876543210987654321098765432109876543210987654321098765432109876543210987654321098765432109876543210987654321', 0)]) as large_min_aggregation,

    arrayMax([toDecimal512('999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999', 0),
              toDecimal512('123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789012345678901234567890123456789', 0),
              toDecimal512('987654321098765432109876543210987654321098765432109876543210987654321098765432109876543210987654321098765432109876543210987654321', 0)]) as large_max_aggregation;

-- ==============================================
-- 4. 复杂条件查询测试
-- ==============================================

SELECT '=== 复杂条件查询测试 ===' as test_section;
DROP TABLE IF EXISTS test_decimal512_table;
CREATE TABLE IF NOT EXISTS test_decimal512_table (
    id UInt32,
    token_balance Decimal512(18),
    transaction_amount Decimal512(8),
    gas_fee Decimal512(8)
)ENGINE=Memory;

INSERT INTO test_decimal512_table VALUES
(1, toDecimal512(1000, 0), toDecimal512(500, 0), toDecimal512(5, 0)),
(2, toDecimal512(2000, 0), toDecimal512(500, 0), toDecimal512(5, 0)),
(3, toDecimal512(1000, 0), toDecimal512(5000, 0), toDecimal512(50, 0)),
(4, toDecimal512(10000, 0), toDecimal512(1000, 0), toDecimal512(10, 0)),
(5, toDecimal512(1000, 0), toDecimal512(50, 0), toDecimal512(5, 0)),
(6, toDecimal512(5000, 0), toDecimal512(200, 0), toDecimal512(2, 0)),
(7, toDecimal512(5000, 0), toDecimal512(5000, 0), toDecimal512(60, 0)),
(8, toDecimal512(30000, 0), toDecimal512(2000, 0), toDecimal512(20, 0)),
(9, toDecimal512(100, 0), toDecimal512(200, 0), toDecimal512(2, 0)),
(10, toDecimal512(1000, 0), toDecimal512(10, 0), toDecimal512(1, 0));

-- 4.1 复杂范围查询测试
SELECT '------';
SELECT * FROM test_decimal512_table
WHERE (id BETWEEN 1 AND 5)
AND (gas_fee BETWEEN 1 AND 10)
OR (transaction_amount BETWEEN 100 AND 200);
SELECT '------';
-- 4.2 复杂子查询条件测试
SELECT * FROM test_decimal512_table WHERE
id IN (SELECT id FROM test_decimal512_table WHERE token_balance >= 1000);
SELECT '------';
-- 4.3 函数、表达式参与条件
SELECT * FROM test_decimal512_table WHERE
transaction_amount / gas_fee = toDecimal512(100, 0)
AND token_balance > toDecimal512(1000, 0);
SELECT '------';
-- ==============================================
-- 5. 不同类型之间的比较运算测试
-- ==============================================

SELECT '=== 不同类型之间的比较运算测试 ===' as test_section;

-- 5.1 与整数类型比较
SELECT
    toDecimal512('1000000.000000000000000000', 18) = 1000000 as decimal512_equals_int,
    toDecimal512('1000000.000000000000000000', 18) > 500000 as decimal512_greater_than_int,
    toDecimal512('1000000.000000000000000000', 18) < 2000000 as decimal512_less_than_int,
    toDecimal512('1000000.000000000000000000', 18) >= 1000000 as decimal512_greater_equal_int,
    toDecimal512('1000000.000000000000000000', 18) <= 1000000 as decimal512_less_equal_int,
    toDecimal512('1000000.000000000000000000', 18) != 500000 as decimal512_not_equal_int;

-- 5.2 与不同精度整数类型比较
SELECT
    toDecimal512('9223372036854775807.000000000000000000', 18) = 9223372036854775807 as decimal512_equals_int64_max,
    toDecimal512('18446744073709551615.000000000000000000', 18) = 18446744073709551615 as decimal512_equals_uint64_max,
    toDecimal512('170141183460469231731687303715884105727.000000000000000000', 18) = 170141183460469231731687303715884105727 as decimal512_equals_int128_max;

-- 5.3 与Decimal32类型比较
SELECT
    toDecimal512('100000.000000000000000000', 18) = toDecimal32('100000.00', 2) as decimal512_equals_decimal32,
    toDecimal512('100000.000000000000000000', 18) > toDecimal32('500000.00', 2) as decimal512_greater_than_decimal32,
    toDecimal512('100000.000000000000000000', 18) < toDecimal32('200000.00', 2) as decimal512_less_than_decimal32,
    toDecimal512('100000.000000000000000000', 18) >= toDecimal32('100000.00', 2) as decimal512_greater_equal_decimal32,
    toDecimal512('100000.000000000000000000', 18) <= toDecimal32('100000.00', 2) as decimal512_less_equal_decimal32,
    toDecimal512('100000.000000000000000000', 18) != toDecimal32('500000.00', 2) as decimal512_not_equal_decimal32;
-- 1	0	1	1	1	1

-- 5.4 与Decimal64类型比较
SELECT
    toDecimal512('1000000.000000000000000000', 18) = toDecimal64('1000000.00000000000', 11) as decimal512_equals_decimal64,
    toDecimal512('1000000.000000000000000000', 18) > toDecimal64('500000.00000000000', 11) as decimal512_greater_than_decimal64,
    toDecimal512('1000000.000000000000000000', 18) < toDecimal64('2000000.00000000000', 11) as decimal512_less_than_decimal64,
    toDecimal512('1000000.000000000000000000', 18) >= toDecimal64('1000000.00000000000', 11) as decimal512_greater_equal_decimal64,
    toDecimal512('1000000.000000000000000000', 18) <= toDecimal64('1000000.00000000000', 11) as decimal512_less_equal_decimal64,
    toDecimal512('1000000.000000000000000000', 18) != toDecimal64('500000.00000000000', 11) as decimal512_not_equal_decimal64;
-- 1	1	1	1	1	1

-- 5.5 与Decimal128类型比较
SELECT
    toDecimal512('1000000.000000000000000000', 18) = toDecimal128('1000000.000000000000000000', 18) as decimal512_equals_decimal128,
    toDecimal512('1000000.000000000000000000', 18) > toDecimal128('500000.000000000000000000', 18) as decimal512_greater_than_decimal128,
    toDecimal512('1000000.000000000000000000', 18) < toDecimal128('2000000.000000000000000000', 18) as decimal512_less_than_decimal128,
    toDecimal512('1000000.000000000000000000', 18) >= toDecimal128('1000000.000000000000000000', 18) as decimal512_greater_equal_decimal128,
    toDecimal512('1000000.000000000000000000', 18) <= toDecimal128('1000000.000000000000000000', 18) as decimal512_less_equal_decimal128,
    toDecimal512('1000000.000000000000000000', 18) != toDecimal128('500000.000000000000000000', 18) as decimal512_not_equal_decimal128;


-- 5.6 与Decimal256类型比较
SELECT
    toDecimal512('1000000.000000000000000000', 18) = toDecimal256('1000000.000000000000000000', 18) as decimal512_equals_decimal256,
    toDecimal512('1000000.000000000000000000', 18) > toDecimal256('500000.000000000000000000', 18) as decimal512_greater_than_decimal256,
    toDecimal512('1000000.000000000000000000', 18) < toDecimal256('2000000.000000000000000000', 18) as decimal512_less_than_decimal256,
    toDecimal512('1000000.000000000000000000', 18) >= toDecimal256('1000000.000000000000000000', 18) as decimal512_greater_equal_decimal256,
    toDecimal512('1000000.000000000000000000', 18) <= toDecimal256('1000000.000000000000000000', 18) as decimal512_less_equal_decimal256,
    toDecimal512('1000000.000000000000000000', 18) != toDecimal256('500000.000000000000000000', 18) as decimal512_not_equal_decimal256;

-- 5.7 不同精度Decimal类型比较
SELECT
    toDecimal512('1000000.000000000000000000', 18) = toDecimal32('1000000.0', 1) as decimal512_equals_decimal32_different_precision,
    toDecimal512('1000000.000000000000000000', 18) = toDecimal64('1000000.00000000000', 11) as decimal512_equals_decimal64_same_precision,
    toDecimal512('1000000.000000000000000000', 18) = toDecimal128('1000000.000000000000000000', 18) as decimal512_equals_decimal128_same_precision,
    toDecimal512('1000000.000000000000000000', 18) = toDecimal256('1000000.000000000000000000', 18) as decimal512_equals_decimal256_same_precision;

-- 5.8 边界值跨类型比较
SELECT
    toDecimal512('9999999.9', 1) = toDecimal32('9999999.9', 1) as decimal512_equals_decimal32_boundary,
    toDecimal512('9999999999999999.99', 2) = toDecimal64('9999999999999999.99', 2) as decimal512_equals_decimal64_boundary,
    toDecimal512('999999999999999999999999999999999999.99', 2) = toDecimal128('999999999999999999999999999999999999.99', 2) as decimal512_equals_decimal128_boundary;

-- 5.9 零值跨类型比较
SELECT
    toDecimal512('0.000000000000000000', 18) = toDecimal32('0.0000000', 8) as decimal512_equals_decimal32_zero,
    toDecimal512('0.000000000000000000', 18) = toDecimal64('0.00000000000000000', 18) as decimal512_equals_decimal64_zero,
    toDecimal512('0.000000000000000000', 18) = toDecimal128('0.000000000000000000', 18) as decimal512_equals_decimal128_zero,
    toDecimal512('0.000000000000000000', 18) = toDecimal256('0.000000000000000000', 18) as decimal512_equals_decimal256_zero,
    toDecimal512('0.000000000000000000', 18) = 0 as decimal512_equals_int_zero;

-- 5.10 负数跨类型比较
SELECT
    toDecimal512('-1000000.000000000000000000', 18) = toDecimal32('-1000000.0', 1) as decimal512_equals_decimal32_negative,
    toDecimal512('-1000000.000000000000000000', 18) = toDecimal64('-1000000.00000000000', 11) as decimal512_equals_decimal64_negative,
    toDecimal512('-1000000.000000000000000000', 18) = toDecimal128('-1000000.00000000000', 11) as decimal512_equals_decimal128_negative,
    toDecimal512('-1000000.000000000000000000', 18) = toDecimal256('-1000000.000000000000000000', 18) as decimal512_equals_decimal256_negative,
    toDecimal512('-1000000.000000000000000000', 18) = -1000000 as decimal512_equals_int_negative;

-- 5.11 区块链场景跨类型比较
SELECT
    -- 代币余额比较
    toDecimal512('1000000.000000000000000000', 18) = toDecimal128('1000000.000000000000000000', 18) as token_balance_decimal512_equals_decimal128,
    toDecimal512('1000000.000000000000000000', 18) > toDecimal64('500000.000000000000', 12) as token_balance_decimal512_greater_than_decimal64,

    -- Gas费用比较
    toDecimal512('21000.0000000000000', 18) = toDecimal32('21000.000', 3) as gas_fee_decimal512_equals_decimal32,
    toDecimal512('21000.0000000000000', 18) < toDecimal64('50000.0000000', 7) as gas_fee_decimal512_less_than_decimal64,

    -- 区块奖励比较
    toDecimal512('6.250000', 6) = toDecimal32('6.2500000', 8) as block_reward_decimal512_equals_decimal32,
    toDecimal512('6.250000', 6) > toDecimal64('2.000000', 6) as block_reward_decimal512_greater_than_decimal64
    ;

-- ==============================================
-- 6. 不同类型之间的运算测试
-- ==============================================

SELECT '=== 不同类型之间的运算测试 ===' as test_section;

-- 6.1 与整数类型运算
SELECT
    toDecimal512('1000000.000000000000000000', 18) + 1000 as decimal_plus_int,
    toDecimal512('1000000.000000000000000000', 18) - 1000 as decimal_minus_int,
    toDecimal512('1000000.000000000000000000', 18) * 2 as decimal_multiply_int,
    toDecimal512('1000000.000000000000000000', 18) / 2 as decimal_divide_int;

-- 6.2 与其他Decimal类型运算
SELECT
    toDecimal512('1000000.000000000000000000', 18) + toDecimal128('500000.000000000000000000', 18) as decimal512_plus_decimal128,
    toDecimal512('1000000.000000000000000000', 18) - toDecimal64('500000.000000000000', 12) as decimal512_minus_decimal64,
    toDecimal512('1000000.000000000000000000', 18) * toDecimal32('2.0000000', 7) as decimal512_multiply_decimal32
    ;

-- 6.3 与浮点数类型运算（应该失败，需要显式转换）
SELECT
    toDecimal512('1000.500000000000000000', 18) = toFloat64(1000.5) as decimal_plus_float,
    toDecimal512('500.250000000000000000', 18) = toFloat32(500.25) as decimal_minus_float,
    toDecimal512('1234.567', 3) > toFloat32(2345.678),
    toDecimal512('9876.54321098765', 11) < toFloat64(1234.56789012345);

-- ==============================================
-- 6. 边界值比较测试
-- ==============================================

SELECT '=== 边界值比较测试 ===' as test_section;

-- 6.1 最大值比较
SELECT
    toDecimal512('999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999', 0) =
    toDecimal512('999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999', 0) as max_value_equality,

    toDecimal512('999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999', 0) >
    toDecimal512('999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999998', 0) as max_value_greater;

-- 6.2 最小值比较
SELECT
    toDecimal512('-999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999', 0) =
    toDecimal512('-999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999', 0) as min_value_equality,

    toDecimal512('-999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999', 0) <
    toDecimal512('-999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999999998', 0) as min_value_less;

-- 6.3 零值比较
SELECT
    toDecimal512('0', 0) = toDecimal512('0.0', 1) as zero_equality,
    toDecimal512('0', 0) > toDecimal512('-1', 0) as zero_greater_negative,
    toDecimal512('0', 0) < toDecimal512('1', 0) as zero_less_positive;

-- 测试完成标记
SELECT '=== Decimal512 比较运算测试完成 ===' as test_completion;
